(54, 'Đêm Nhạc Thiện Nguyện: Ánh Sáng Cho Em', 'OFFLINE', 'Nhà Hát Hòa Bình, TP.HCM', 'Khán phòng chính', ST_GeomFromText('POINT(106.677 10.775)', 4326), '<h3>Gây quỹ phẫu thuật mắt</h3><p>Với sự góp mặt của nhiều ngôi sao nổi tiếng. Toàn bộ tiền vé sẽ được quyên góp.</p>', 5.0, 5000.0, 'APPROVED', NULL, 'https://images.unsplash.com/photo-1514525253161-7a46d19cd819?auto=format&fit=crop&w=1280&h=720&q=80', 'evt/thumb54', 'https://images.unsplash.com/photo-1459749411175-04bf5292ceea?auto=format&fit=crop&w=720&h=958&q=80', 'evt/poster54', false, '2026-04-30 08:00:00', '2026-05-05 08:00:00', 10, 39, NULL),
(55, 'Workshop Online: Viết Lách Và Kể Chuyện', 'ONLINE', NULL, NULL, NULL, '<h3>Khóa Học Content</h3><p>Cùng nhà văn nổi tiếng rèn luyện kỹ năng storytelling thu hút người đọc.</p>', 5.0, 5000.0, 'APPROVED', NULL, 'https://images.unsplash.com/photo-1455390582262-044cdead2708?auto=format&fit=crop&w=1280&h=720&q=80', 'evt/thumb55', 'https://images.unsplash.com/photo-1519681393784-d120267933ba?auto=format&fit=crop&w=720&h=958&q=80', 'evt/poster55', true, '2026-05-15 09:00:00', '2026-05-20 09:00:00', 6, 23, NULL),
