(58, 'Khóa Tu Mùa Hè 2026', 'OFFLINE', 'Chùa Ba Vàng, Sa Pa', 'Khu Thiền Viện', ST_GeomFromText('POINT(103.832 22.336)', 4326), '<h3>Thanh Lọc Tâm Hồn</h3><p>Chương trình khóa tu 3 ngày giúp bạn tìm lại sự bình yên trong cuộc sống bận rộn.</p>', 5.0, 5000.0, 'APPROVED', NULL, 'https://images.unsplash.com/photo-1544367567-0f2fcb009e0b?auto=format&fit=crop&w=1280&h=720&q=80', 'evt/thumb58', 'https://images.unsplash.com/photo-1507699622108-4be3abd695ad?auto=format&fit=crop&w=720&h=958&q=80', 'evt/poster58', false, '2026-04-01 08:00:00', '2026-04-05 08:00:00', 10, 21, NULL),
(59, 'Webinar Dinh Dưỡng: Ăn Gì Để Trẻ Lâu?', 'ONLINE', NULL, NULL, NULL, '<h3>Kiến Thức Sức Khỏe</h3><p>Chuyên gia dinh dưỡng hướng dẫn xây dựng thực đơn khoa học, lành mạnh mỗi ngày.</p>', 5.0, 5000.0, 'APPROVED', NULL, 'https://images.unsplash.com/photo-1490645935967-10de6ba17061?auto=format&fit=crop&w=1280&h=720&q=80', 'evt/thumb59', 'https://images.unsplash.com/photo-1512621776951-a57141f2eefd?auto=format&fit=crop&w=720&h=958&q=80', 'evt/poster59', true, '2026-03-25 09:00:00', '2026-03-30 09:00:00', 4, 32, NULL),
