(61, 'Hội Thảo Bất Động Sản 2026', 'OFFLINE', 'Vinpearl Landmark 81, TP.HCM', 'Phòng Hội Nghị Tầng 2', ST_GeomFromText('POINT(106.721 10.792)', 4326), '<h3>Xu hướng đầu tư</h3><p>Toàn cảnh thị trường BĐS và cơ hội đầu tư vùng ven hậu đại dịch.</p>', 5.0, 5000.0, 'PENDING', NULL, 'https://images.unsplash.com/photo-1560518883-ce09059eeffa?auto=format&fit=crop&w=1280&h=720&q=80', 'evt/thumb61', 'https://images.unsplash.com/photo-1486406146926-c627a92ad1ab?auto=format&fit=crop&w=720&h=958&q=80', 'evt/poster61', true, '2026-02-07 09:00:00', '2026-02-12 09:00:00', 3, 34, NULL),
