(63, 'Khóa Học Cắm Hoa Phong Cách Âu', 'OFFLINE', 'Workshop Room, The New Playground, TP.HCM', 'Tầng 1', ST_GeomFromText('POINT(106.700 10.779)', 4326), '<h3>Nghệ Thuật Florist</h3><p>Học cách chọn tone màu, kết cấu và thực hành cắm hoa lẵng, hoa cưới.</p>', 5.0, 5000.0, 'CANCELLED', 'Người hướng dẫn gặp vấn đề sức khỏe', 'https://images.unsplash.com/photo-1526047932273-341f2a7631f9?auto=format&fit=crop&w=1280&h=720&q=80', 'evt/thumb63', 'https://images.unsplash.com/photo-1452860606245-08befc0ff44b?auto=format&fit=crop&w=720&h=958&q=80', 'evt/poster63', false, '2026-05-05 09:00:00', '2026-05-10 09:00:00', 6, 14, NULL),
(64, 'Livestream: Chữa Bài IELTS Writing Task 2', 'ONLINE', NULL, NULL, NULL, '<h3>Học tiếng Anh</h3><p>Sửa lỗi sai thường gặp và chiến thuật ăn điểm chí mạng trong bài thi viết.</p>', 5.0, 5000.0, 'APPROVED', NULL, 'https://images.unsplash.com/photo-1456406644174-8ddd4cd52a06?auto=format&fit=crop&w=1280&h=720&q=80', 'evt/thumb64', 'https://images.unsplash.com/photo-1524178232363-1fb2b075b655?auto=format&fit=crop&w=720&h=958&q=80', 'evt/poster64', false, '2026-03-15 10:00:00', '2026-03-20 10:00:00', 6, 23, NULL),
