(78, 'Giải Bóng Chuyền Bãi Biển Toàn Quốc', 'OFFLINE', 'Bãi biển Mỹ Khê, Đà Nẵng', 'Sân bóng chuyền ngoài trời', ST_GeomFromText('POINT(108.243 16.059)', 4326), '<h3>Sôi động mùa hè</h3><p>Cổ vũ cho những đội bóng chuyền xuất sắc nhất từ Bắc chí Nam.</p>', 5.0, 5000.0, 'APPROVED', NULL, 'https://images.unsplash.com/photo-1461896836934-ffe607ba8211?auto=format&fit=crop&w=1280&h=720&q=80', 'evt/thumb78', 'https://images.unsplash.com/photo-1519861531473-920026073336?auto=format&fit=crop&w=720&h=958&q=80', 'evt/poster78', true, '2026-04-15 08:00:00', '2026-04-20 08:00:00', 4, 17, NULL),
(79, 'Webinar: Xây Dựng Thương Hiệu Cá Nhân Trên Mạng Xã Hội', 'ONLINE', NULL, NULL, NULL, '<h3>Khóa Học Nhanh</h3><p>Làm thế nào để trở thành một KOL/Influencer có sức ảnh hưởng thực sự?</p>', 5.0, 5000.0, 'PENDING', NULL, 'https://images.unsplash.com/photo-1611162617474-5b21e879e113?auto=format&fit=crop&w=1280&h=720&q=80', 'evt/thumb79', 'https://images.unsplash.com/photo-1557425955-df376b5903c8?auto=format&fit=crop&w=720&h=958&q=80', 'evt/poster79', true, '2026-03-20 09:00:00', '2026-03-25 09:00:00', 3, 7, NULL),
