(83, 'Webinar Tối Ưu Tốc Độ Tải Trang ReactJS', 'ONLINE', NULL, NULL, NULL, '<h3>Kiến Thức Lập Trình</h3><p>Các kỹ thuật lazy loading, memoization để tăng hiệu năng ứng dụng Web.</p>', 5.0, 5000.0, 'PENDING', NULL, 'https://images.unsplash.com/photo-1633356122544-f134324a6cee?auto=format&fit=crop&w=1280&h=720&q=80', 'evt/thumb83', 'https://images.unsplash.com/photo-1555066931-4365d14bab8c?auto=format&fit=crop&w=720&h=958&q=80', 'evt/poster83', true, '2026-02-07 08:00:00', '2026-02-12 08:00:00', 2, 16, NULL),
