(85, 'Workshop: Tập Thiền Kết Hợp Trà Đạo', 'OFFLINE', 'Thiền Viện Trúc Lâm, Đà Lạt', 'Sảnh trà đạo', ST_GeomFromText('POINT(108.435 11.916)', 4326), '<h3>An Tĩnh Tâm Hồn</h3><p>Học cách thả lỏng tâm trí, hít thở và thưởng thức trà truyền thống.</p>', 5.0, 5000.0, 'APPROVED', NULL, 'https://images.unsplash.com/photo-1544367567-0f2fcb009e0b?auto=format&fit=crop&w=1280&h=720&q=80', 'evt/thumb85', 'https://images.unsplash.com/photo-1507699622108-4be3abd695ad?auto=format&fit=crop&w=720&h=958&q=80', 'evt/poster85', true, '2026-05-10 10:00:00', '2026-05-15 10:00:00', 4, 21, NULL),
(86, 'Ngày Hội Giao Lưu Khởi Nghiệp Sinh Viên', 'OFFLINE', 'Trường Đại học Bách Khoa, Hà Nội', 'Sân Vận Động', ST_GeomFromText('POINT(105.842 21.005)', 4326), '<h3>Ý Tưởng Startup</h3><p>Sân chơi trưng bày sản phẩm thực tế của các đội nhóm sinh viên khởi nghiệp.</p>', 5.0, 5000.0, 'APPROVED', NULL, 'https://images.unsplash.com/photo-1522071820081-009f0129c71c?auto=format&fit=crop&w=1280&h=720&q=80', 'evt/thumb86', 'https://images.unsplash.com/photo-1556761175-4b46a572b786?auto=format&fit=crop&w=720&h=958&q=80', 'evt/poster86', false, '2026-03-25 09:00:00', '2026-03-30 09:00:00', 3, 23, NULL),
