(89, 'Sự Kiện Đêm Trăng Kể Chuyện Cổ Tích Cùng Các Bé', 'OFFLINE', 'Nhà hát kịch thành phố, TP.HCM', 'Khán phòng thiếu nhi', ST_GeomFromText('POINT(106.697 10.767)', 4326), '<h3>Giải trí gia đình</h3><p>Một buổi tối ý nghĩa nơi bé được đắm chìm vào những câu chuyện cổ tích và kịch rối.</p>', 5.0, 5000.0, 'APPROVED', NULL, 'https://images.unsplash.com/photo-1511895426328-dc8714191300?auto=format&fit=crop&w=1280&h=720&q=80', 'evt/thumb89', 'https://images.unsplash.com/photo-1469571486292-0ba58a3f068b?auto=format&fit=crop&w=720&h=958&q=80', 'evt/poster89', true, '2026-06-15 09:00:00', '2026-06-20 09:00:00', 9, 27, NULL),
(90, 'Livestream: Lựa Chọn Dụng Cụ Pha Cà Phê Thủ Công Dành Cho Người Mới Bắt Đầu', 'ONLINE', NULL, NULL, NULL, '<h3>Kiến Thức Cà Phê</h3><p>Giới thiệu ưu nhược điểm của các dụng cụ như V60, French Press, Aeropress và Moka Pot.</p>', 5.0, 5000.0, 'PENDING', NULL, 'https://images.unsplash.com/photo-1497935586351-b67a49e012bf?auto=format&fit=crop&w=1280&h=720&q=80', 'evt/thumb90', 'https://images.unsplash.com/photo-1511920170033-f8396924c348?auto=format&fit=crop&w=720&h=958&q=80', 'evt/poster90', false, '2026-03-10 10:00:00', '2026-03-15 10:00:00', 5, 40, NULL),
